prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?startBeratung) AS ?beratungCount)
       (COUNT(DISTINCT ?startAndReachBezahl) AS ?beratungThatReachBezahlCount)
WHERE {
  ?model tai:originalId "0ae2e7d8093840cc8a65c475b6275cae" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?beratung a bboExt:ChoreographyTask ;
            bbo:name ?beratungName ;
            tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?beratungName)), LCASE("beratung")))

  ?bezahl a ?bezahlType ;
          bbo:name ?bezahlName ;
          tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?bezahlName)), LCASE("bezahlvorgang")))

  BIND(?beratung AS ?startBeratung)

  FILTER EXISTS {
    ?startBeratung ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?bezahl .
  }
  BIND(?beratung AS ?startAndReachBezahl)
}
GROUP BY 1

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?beratung) AS ?beratungCount)
       (COUNT(DISTINCT ?beratungWithReach) AS ?beratungThatReachBezahlCount)
WHERE {
  ?model tai:originalId "0ae2e7d8093840cc8a65c475b6275cae" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?beratung a bboExt:ChoreographyTask ;
            bbo:name ?beratungName ;
            tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?beratungName)), LCASE("beratung")))

  ?bezahl a ?bezahlType ;
          bbo:name ?bezahlName ;
          tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?bezahlName)), LCASE("bezahlvorgang")))

  BIND(?beratung AS ?beratungWithReach)
  FILTER EXISTS {
    ?beratung ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?bezahl .
  }
}
GROUP BY ()

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?beratungCount ?beratungThatReachBezahlCount WHERE {
  {
    SELECT (COUNT(DISTINCT ?beratung) AS ?beratungCount) WHERE {
      ?model tai:originalId "0ae2e7d8093840cc8a65c475b6275cae" .
      ?defs tai:belongsTo ?model .
      ?choreo tai:belongsTo ?defs .

      ?beratung a bboExt:ChoreographyTask ;
                bbo:name ?beratungName ;
                tai:belongsTo ?choreo .
      FILTER(CONTAINS(LCASE(STR(?beratungName)), LCASE("beratung")))
    }
  }
  {
    SELECT (COUNT(DISTINCT ?beratung) AS ?beratungThatReachBezahlCount) WHERE {
      ?model tai:originalId "0ae2e7d8093840cc8a65c475b6275cae" .
      ?defs tai:belongsTo ?model .
      ?choreo tai:belongsTo ?defs .

      ?beratung a bboExt:ChoreographyTask ;
                bbo:name ?beratungName ;
                tai:belongsTo ?choreo .
      FILTER(CONTAINS(LCASE(STR(?beratungName)), LCASE("beratung")))

      ?bezahl a ?bezahlType ;
              bbo:name ?bezahlName ;
              tai:belongsTo ?choreo .
      FILTER(CONTAINS(LCASE(STR(?bezahlName)), LCASE("bezahlvorgang")))

      FILTER EXISTS {
        ?beratung ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?bezahl .
      }
    }
  }
}
